export interface Project {
  id: string;
  name: string;
  description: string;
  status: 'active' | 'paused' | 'completed';
  goals: { id: string; text: string; completed: boolean }[];
  createdAt: Date;
  updatedAt: Date;
}

export interface Note {
  id: string;
  title: string;
  content: string;
  workspace: string; // e.g., 'Learning', 'Personal', 'Work'
  projectId?: string; // Relation to Project
  tags: string[];
  createdAt: Date;
  updatedAt: Date;
  date: string; // YYYY-MM-DD
  attachments: string[]; // Paths or local object URLs to Resources
}

export interface Task {
  id: string;
  noteId?: string; // Optional if created within a note
  projectId?: string; // Relation to Project
  text: string;
  completed: boolean;
  rolloverCount: number;
  priority: 'low' | 'medium' | 'high';
  createdAt: Date;
  dueDate?: string; // YYYY-MM-DD
}

export interface Resource {
  id: string;
  name: string;
  type: string; // MIME type
  size: number; // Bytes
  path: string; // Local sandboxed file path or object URL
  projectId?: string;
  createdAt: Date;
}

export interface WeeklyReview {
  id: string; // e.g., "2026-W29"
  week: number;
  year: number;
  summary: string;
  generated: boolean;
  edited: boolean;
}

export interface Settings {
  id: 'global';
  theme: 'dark' | 'light';
  githubTokenEncrypted?: string;
  githubRepo?: string;
  weeklyReminder: boolean;
  notifications: boolean;
  lastSyncAt?: Date;
}

import Dexie, { type Table } from 'dexie';
import { Project, Note, Task, Resource, WeeklyReview, Settings } from './schema';

class NorthgateDatabase extends Dexie {
  projects!: Table<Project, string>;
  notes!: Table<Note, string>;
  tasks!: Table<Task, string>;
  resources!: Table<Resource, string>;
  weeklyReviews!: Table<WeeklyReview, string>;
  settings!: Table<Settings, string>;

  constructor() {
    super('NorthgateDB');

    this.version(1).stores({
      projects: 'id, name, status, createdAt, updatedAt',
      notes: 'id, title, workspace, projectId, date, *tags, createdAt, updatedAt',
      tasks: 'id, noteId, projectId, completed, priority, dueDate',
      resources: 'id, name, type, projectId, createdAt',
      weeklyReviews: 'id, week, year',
      settings: 'id'
    });
  }
}

export const db = new NorthgateDatabase();

const ALGORITHM = 'AES-GCM';
const PBKDF2_ITERATIONS = 100000;

async function getDerivedKey(passphrase: string, salt: Uint8Array): Promise<CryptoKey> {
  const encoder = new TextEncoder();
  const baseKey = await window.crypto.subtle.importKey(
    'raw',
    encoder.encode(passphrase),
    'PBKDF2',
    false,
    ['deriveKey']
  );

  return window.crypto.subtle.deriveKey(
    {
      name: 'PBKDF2',
      salt,
      iterations: PBKDF2_ITERATIONS,
      hash: 'SHA-256'
    },
    baseKey,
    { name: ALGORITHM, length: 256 },
    false,
    ['encrypt', 'decrypt']
  );
}

export async function encryptToken(token: string, deviceId: string): Promise<string> {
  const encoder = new TextEncoder();
  const salt = window.crypto.getRandomValues(new Uint8Array(16));
  const iv = window.crypto.getRandomValues(new Uint8Array(12));
  const key = await getDerivedKey(deviceId, salt);

  const encrypted = await window.crypto.subtle.encrypt(
    { name: ALGORITHM, iv },
    key,
    encoder.encode(token)
  );

  const combined = new Uint8Array(salt.length + iv.length + encrypted.byteLength);
  combined.set(salt, 0);
  combined.set(iv, salt.length);
  combined.set(new Uint8Array(encrypted), salt.length + iv.length);

  return btoa(String.fromCharCode(...combined));
}

export async function decryptToken(encryptedBase64: string, deviceId: string): Promise<string> {
  const decoder = new TextDecoder();
  const binaryString = atob(encryptedBase64);
  const combined = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    combined[i] = binaryString.charCodeAt(i);
  }

  const salt = combined.slice(0, 16);
  const iv = combined.slice(16, 28);
  const data = combined.slice(28);

  const key = await getDerivedKey(deviceId, salt);
  const decrypted = await window.crypto.subtle.decrypt(
    { name: ALGORITHM, iv },
    key,
    data
  );

  return decoder.decode(decrypted);
}

export function getOrCreateDeviceId(): string {
  let id = localStorage.getItem('ng_device_id');
  if (!id) {
    id = crypto.randomUUID();
    localStorage.setItem('ng_device_id', id);
  }
  return id;
}

import { create } from 'zustand';
import { db } from '../database/dexie';
import { Project, Note, Task, Settings } from '../database/schema';

interface NorthgateStore {
  activeWorkspace: string;
  activeProjectId: string | null;
  projects: Project[];
  recentNotes: Note[];
  todayTasks: Task[];
  settings: Settings | null;
  streak: number;
  isLoading: boolean;

  initialize: () => Promise<void>;
  setActiveWorkspace: (workspace: string) => void;
  setActiveProjectId: (projectId: string | null) => void;
  addProject: (project: Omit<Project, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
  updateProject: (id: string, updates: Partial<Project>) => Promise<void>;
  addNote: (note: Omit<Note, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
  addTask: (task: Omit<Task, 'id' | 'createdAt' | 'rolloverCount'>) => Promise<void>;
  toggleTask: (id: string, completed: boolean) => Promise<void>;
  calculateStreak: () => Promise<void>;
}

export const useNorthgateStore = create<NorthgateStore>((set, get) => ({
  activeWorkspace: 'All',
  activeProjectId: null,
  projects: [],
  recentNotes: [],
  todayTasks: [],
  settings: null,
  streak: 0,
  isLoading: true,

  initialize: async () => {
    set({ isLoading: true });
    let settings = await db.settings.get('global');
    if (!settings) {
      settings = {
        id: 'global',
        theme: 'dark',
        weeklyReminder: true,
        notifications: false,
      };
      await db.settings.add(settings);
    }

    const projects = await db.projects.toArray();
    const recentNotes = await db.notes.orderBy('updatedAt').reverse().limit(10).toArray();
    const todayStr = new Date().toISOString().split('T')[0];
    const todayTasks = await db.tasks.filter(t => t.dueDate === todayStr).toArray();

    set({
      projects,
      recentNotes,
      todayTasks,
      settings,
      isLoading: false,
    });
    await get().calculateStreak();
  },

  setActiveWorkspace: (workspace) => set({ activeWorkspace: workspace }),
  setActiveProjectId: (projectId) => set({ activeProjectId: projectId }),

  addProject: async (projectData) => {
    const newProject: Project = {
      ...projectData,
      id: crypto.randomUUID(),
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    await db.projects.add(newProject);
    set((state) => ({ projects: [...state.projects, newProject] }));
  },

  updateProject: async (id, updates) => {
    const updatedFields = { ...updates, updatedAt: new Date() };
    await db.projects.update(id, updatedFields);
    set((state) => ({ 
      projects: state.projects.map((p) => (p.id === id ? { ...p, ...updatedFields } : p)),
    }));
  },

  addNote: async (noteData) => {
    const newNote: Note = {
      ...noteData,
      id: crypto.randomUUID(),
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    await db.notes.add(newNote);
    const recentNotes = await db.notes.orderBy('updatedAt').reverse().limit(10).toArray();
    set({ recentNotes });
  },

  addTask: async (taskData) => {
    const newTask: Task = {
      ...taskData,
      id: crypto.randomUUID(),
      rolloverCount: 0,
      createdAt: new Date(),
    };
    await db.tasks.add(newTask);
    const todayStr = new Date().toISOString().split('T')[0];
    const todayTasks = await db.tasks.filter(t => t.dueDate === todayStr).toArray();
    set({ todayTasks });
  },

  toggleTask: async (id, completed) => {
    await db.tasks.update(id, { completed });
    set((state) => ({ 
      todayTasks: state.todayTasks.map((t) => (t.id === id ? { ...t, completed } : t)),
    }));
  },

  calculateStreak: async () => {
    const notes = await db.notes.toArray();
    if (notes.length === 0) {
      set({ streak: 0 });
      return;
    }
    const uniqueDates = Array.from(new Set(notes.map((n) => n.date))).sort(
      (a, b) => new Date(b).getTime() - new Date(a).getTime()
    );
    let currentStreak = 0;
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    const mostRecentNoteDate = new Date(uniqueDates[0]);
    mostRecentNoteDate.setHours(0, 0, 0, 0);

    if (mostRecentNoteDate.getTime() < yesterday.getTime()) {
      set({ streak: 0 });
      return;
    }
    let checkDate = mostRecentNoteDate;
    for (let i = 0; i < uniqueDates.length; i++) {
      const noteDate = new Date(uniqueDates[i]);
      noteDate.setHours(0, 0, 0, 0);
      const diffTime = Math.abs(checkDate.getTime() - noteDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      if (diffDays <= 1) {
        currentStreak++;
        checkDate = noteDate;
      } else {
        break;
      }
    }
    set({ streak: currentStreak });
  }
}));

import { db } from '../database/dexie';
import { Note, Project } from '../database/schema';
import { decryptToken, getOrCreateDeviceId } from '../utils/crypto';

interface SyncPayload {
  path: string;
  content: string;
  sha?: string;
}

export class GitHubSyncService {
  private static async getDecryptedToken(): Promise<string | null> {
    const settings = await db.settings.get('global');
    if (!settings || !settings.githubTokenEncrypted) return null;
    try {
      const deviceId = getOrCreateDeviceId();
      return await decryptToken(settings.githubTokenEncrypted, deviceId);
    } catch (e) {
      console.error('Failed to decrypt GitHub Token', e);
      return null;
    }
  }

  private static formatNotePath(note: Note): string {
    const dateObj = new Date(note.date);
    const year = dateObj.getFullYear();
    const month = String(dateObj.getMonth() + 1).padStart(2, '0');
    const sanitizedTitle = note.title
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/(^-|-$)/g, '');
    return `notes/${year}/${month}/${note.date}/${sanitizedTitle || 'untitled'}.md`;
  }

  private static serializeNote(note: Note, project?: Project): string {
    return [
      '---',
      `id: "${note.id}"`,
      `title: "${note.title.replace(/"/g, '\\"')}"`,
      `date: "${note.date}"`,
      `workspace: "${note.workspace}"`,
      project ? `project: "${project.name}"` : 'project: null',
      `tags: [${note.tags.map((t) => `"${t}"`).join(', ')}]`,
      `updatedAt: "${note.updatedAt.toISOString()}"`,
      '---',
      '',
      note.content,
    ].join('\n');
  }

  private static async getFileSHA(token: string, repo: string, path: string): Promise<string | null> {
    try {
      const response = await fetch(`https://api.github.com/repos/${repo}/contents/${path}`, {
        headers: {
          Authorization: `Bearer ${token}`,
          Accept: 'application/vnd.github.v3+json',
        },
      });
      if (response.status === 200) {
        const data = await response.json();
        return data.sha;
      }
      return null;
    } catch {
      return null;
    }
  }

  public static async pushFile(path: string, content: string, message: string): Promise<boolean> {
    const token = await this.getDecryptedToken();
    const settings = await db.settings.get('global');
    if (!token || !settings?.githubRepo) return false;

    const sha = await this.getFileSHA(token, settings.githubRepo, path);
    const payload: SyncPayload = { path, content };
    if (sha) payload.sha = sha;

    try {
      const response = await fetch(`https://api.github.com/repos/${settings.githubRepo}/contents/${path}`, {
        method: 'PUT',
        headers: {
          Authorization: `Bearer ${token}`,
          Accept: 'application/vnd.github.v3+json',
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          message,
          content: btoa(unescape(encodeURIComponent(content))),
          sha: payload.sha,
        }),
      });
      if (response.ok) {
        await db.settings.update('global', { lastSyncAt: new Date() });
        return true;
      }
      return false;
    } catch (error) {
      console.error('Push failed', error);
      return false;
    }
  }

  public static async syncPendingNotes(): Promise<{ success: number; failed: number }> {
    const results = { success: 0, failed: 0 };
    const notes = await db.notes.toArray();
    for (const note of notes) {
      const project = note.projectId ? await db.projects.get(note.projectId) : undefined;
      const path = this.formatNotePath(note);
      const content = this.serializeNote(note, project);
      const isSuccess = await this.pushFile(path, content, `Sync Note: ${note.title}`);
      if (isSuccess) results.success++;
      else results.failed++;
    }
    return results;
  }
}
